class Shipment:
    """Base class for all shipment types."""

    name = "base"

    def process(self, record):
        """Handle incoming data and produce a result."""
        dest = record.get("dest", "unknown")
        return {"name": self.name, "dest": dest, "status": "processed"}

    def label(self):
        return f"SHIP-{self.name.upper()}"

