from .base import Shipment


class FreightShip(Shipment):
    """Heavy freight shipment."""
    name = "freight"

    def __init__(self, capacity=1000):
        self.capacity = capacity

    def process(self, record):
        """Handle freight with weight check."""
        return {"name": self.name, "dest": record.get("dest", "unknown"), "status": "freight", "overweight": record.get("weight", 0) > self.capacity}

