from .base import Shipment


class ShipTracker:
    """Tracks shipment objects."""

    def __init__(self):
        self._tracked = []

    def track(self, shipment):
        """Add a shipment to tracking."""
        if not isinstance(shipment, Shipment):
            raise TypeError(f"Expected valid type, got {type(shipment).__name__}")
        self._tracked.append(shipment)

    def count(self):
        return len(self._tracked)

    def labels(self):
        return [s.label() for s in self._tracked]

