class ShipRouter:
    """Routes shipments to their destination handler."""

    def __init__(self):
        self._routes = {}

    def add_route(self, dest, shipment):
        self._routes[dest] = shipment

    def route(self, dest, info):
        """Route info to the shipment handler for dest."""
        shipment = self._routes.get(dest)
        if shipment is None:
            raise KeyError(f"No route for: {dest}")
        return shipment.process(info)

    def destinations(self):
        return list(self._routes.keys())

