class Warehouse:
    """Stores shipments and dispatches them."""

    def __init__(self):
        self._shipments = []

    def store(self, shipment):
        self._shipments.append(shipment)

    def dispatch_all(self, info):
        """Dispatch all stored shipments with the given info."""
        return [s.process(info) for s in self._shipments]

    def count(self):
        return len(self._shipments)

