from .base import Shipment


class ShipInspector:
    """Inspects and validates shipments."""

    def inspect(self, shipment, info):
        """Inspect a shipment by dispatching and checking result."""
        if not isinstance(shipment, Shipment):
            raise TypeError(f"Expected valid type, got {type(shipment).__name__}")
        result = shipment.process(info)
        result["inspected"] = True
        return result
